import { useState } from "react";

export default function Administer() {
  const [form, setForm] = useState({});

  const submit = async () => {
    await fetch("http://10.250.12.50:5000/administer", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(form),
    });

    alert("Dose Recorded & Certificate Generated");
  };

  return (
    <div className="card">
      <h2>Administer Dose</h2>

      <input placeholder="Citizen ID" onChange={(e) => setForm({ ...form, citizen_id: e.target.value })} />
      <input placeholder="Dose Number" onChange={(e) => setForm({ ...form, dose_number: e.target.value })} />
      <input placeholder="Center ID" onChange={(e) => setForm({ ...form, center_id: e.target.value })} />

      <button onClick={submit}>Record</button>
    </div>
  );
}
